/**
 * Form Validation Utilities
 *
 * クライアント側のバリデーション関数を提供します。
 * すべてのバリデーションはサーバー側でも実施されます（セキュリティ）。
 * クライアント側バリデーションはUX向上のためのみです。
 *
 * バリデーションルール:
 * - Email: RFC 5322準拠、最大255文字
 * - Password: 8-128文字、大文字小文字数字特殊文字を各1文字以上含む
 */

import type { LoginFormData, RegisterFormData, ForgotPasswordFormData, FormErrors } from '../types';

// ============================================================================
// Email Validation
// ============================================================================

/**
 * メールバリデーションルール
 */
export const emailValidation = {
  // HTML5仕様のパターン（簡略化されているが実用的）
  pattern: /^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i,
  maxLength: 255,
  minLength: 5, // "a@b.c" minimum
  errorMessages: {
    required: 'Email is required',
    format: 'Invalid email address format',
    minLength: 'Email must be at least 5 characters',
    maxLength: 'Email must be less than 255 characters',
    alreadyRegistered: 'Email is already registered',
  },
};

/**
 * メール形式をバリデーション
 * @param email - バリデーション対象のメールアドレス
 * @returns 無効の場合はエラーメッセージ、有効の場合は空文字列
 */
export const validateEmailFormat = (email: string): string => {
  if (!email) return emailValidation.errorMessages.required;
  if (email.length < emailValidation.minLength) return emailValidation.errorMessages.minLength;
  if (email.length > emailValidation.maxLength) return emailValidation.errorMessages.maxLength;
  if (!emailValidation.pattern.test(email)) return emailValidation.errorMessages.format;
  return ''; // Valid
};

// ============================================================================
// Password Validation
// ============================================================================

/**
 * パスワードバリデーションルール（クライアント側）
 * spec002 OpenAPI契約で定義されたバックエンド要件と一致する必要があります。
 *
 * 要件:
 * - 最小8文字
 * - 最大128文字
 * - 少なくとも1つの文字（任意の文字）
 * - 少なくとも1つの数字（0-9）
 */
export const passwordValidation = {
  minLength: 8,
  maxLength: 128,
  patterns: {
    hasLetter: /[\p{L}]/u, // Unicode letter support
    hasNumber: /[0-9]/,
  },
  errorMessages: {
    required: 'Password is required',
    minLength: 'Password must be at least 8 characters',
    maxLength: 'Password must be less than 128 characters',
    letter: 'Password must contain at least one letter',
    number: 'Password must contain at least one number',
  },
};

/**
 * パスワードの強度をバリデーション
 * @param password - バリデーション対象のパスワード
 * @returns エラーメッセージの配列（有効の場合は空）
 */
export const validatePasswordStrength = (password: string): string[] => {
  const errors: string[] = [];

  if (!password) {
    return [passwordValidation.errorMessages.required];
  }

  if (password.length < passwordValidation.minLength) {
    errors.push(passwordValidation.errorMessages.minLength);
  } else if (password.length > passwordValidation.maxLength) {
    errors.push(passwordValidation.errorMessages.maxLength);
  }

  if (!passwordValidation.patterns.hasLetter.test(password)) {
    errors.push(passwordValidation.errorMessages.letter);
  }

  if (!passwordValidation.patterns.hasNumber.test(password)) {
    errors.push(passwordValidation.errorMessages.number);
  }

  return errors;
};

/**
 * パスワード一致をバリデーション
 * @param password - パスワード
 * @param confirmPassword - 確認パスワード
 * @returns 不一致の場合はエラーメッセージ、一致の場合は空文字列
 */
export const validatePasswordMatch = (password: string, confirmPassword: string): string => {
  if (!confirmPassword) {
    return 'Please confirm your password';
  }
  if (password !== confirmPassword) {
    return 'Passwords do not match';
  }
  return ''; // Valid
};

// ============================================================================
// Form Validation
// ============================================================================

/**
 * ログインフォームをバリデーション
 * @param formData - ログインフォームデータ
 * @returns フィールドエラーオブジェクト
 */
export const validateLoginForm = (formData: LoginFormData): FormErrors => {
  const errors: FormErrors = {};

  // Email validation
  const emailError = validateEmailFormat(formData.email);
  if (emailError) {
    errors.email = emailError;
  }

  // Password validation (basic check - no strength requirements for login)
  if (!formData.password) {
    errors.password = passwordValidation.errorMessages.required;
  }

  return errors;
};

/**
 * 登録フォームをバリデーション
 * @param formData - 登録フォームデータ
 * @returns フィールドエラーオブジェクト
 */
export const validateRegisterForm = (formData: RegisterFormData): FormErrors => {
  const errors: FormErrors = {};

  // Email validation
  const emailError = validateEmailFormat(formData.email);
  if (emailError) {
    errors.email = emailError;
  }

  // Password strength validation
  const passwordErrors = validatePasswordStrength(formData.password);
  if (passwordErrors.length > 0) {
    errors.password = passwordErrors.join('. ');
  }

  // Password match validation
  const matchError = validatePasswordMatch(formData.password, formData.confirmPassword);
  if (matchError) {
    errors.confirmPassword = matchError;
  }

  // Terms acceptance validation
  if (!formData.acceptTerms) {
    errors.acceptTerms = 'You must accept the terms and conditions';
  }

  return errors;
};

/**
 * パスワード忘れフォームをバリデーション
 * @param formData - パスワード忘れフォームデータ
 * @returns フィールドエラーオブジェクト
 */
export const validateForgotPasswordForm = (formData: ForgotPasswordFormData): FormErrors => {
  const errors: FormErrors = {};

  // Email validation
  const emailError = validateEmailFormat(formData.email);
  if (emailError) {
    errors.email = emailError;
  }

  return errors;
};

/**
 * パスワード強度インジケーターの計算
 * @param password - パスワード
 * @returns 強度レベル (0-3) と説明文
 */
export const calculatePasswordStrength = (
  password: string
): { strength: number; label: string } => {
  let strength = 0;

  if (password.length >= passwordValidation.minLength) strength++;
  if (password.length >= 12) strength++; // Extra points for longer passwords
  if (passwordValidation.patterns.hasLetter.test(password)) strength++;
  if (passwordValidation.patterns.hasNumber.test(password)) strength++;

  const labels = ['Very Weak', 'Weak', 'Fair', 'Good', 'Strong'];
  return {
    strength,
    label: labels[strength] || 'Very Weak',
  };
};
